// src/views/TabletopView.js
import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import MenuItem from '../components/menu/menuItem';
import Cart from '../components/cart/cart';

// Datos de ejemplo que vendrían de una API
const menuData = [
  { id: 1, name: 'Margarita', category: 'Cócteles', price: 12.50, image: 'margarita.jpg', description: 'Tequila, triple sec, y jugo de lima.' },
  { id: 2, name: 'Papas Fritas', category: 'Aperitivos', price: 6.00, image: 'papas.jpg', description: 'Papas a la francesa con salsa de la casa.' },
];

const TabletopView = () => {
  const { tableId } = useParams();
  const [cartItems, setCartItems] = useState([]);
  const [menu, setMenu] = useState([]);

  useEffect(() => {
    // Aquí harías una llamada a la API para obtener el menú
    setMenu(menuData);
  }, []);

  const handleAddToCart = (item) => {
    setCartItems(prevItems => [...prevItems, item]);
    // Aquí se usaría tecnología en tiempo real (como WebSockets) para notificar a la barra 
    console.log(`Nuevo pedido para la mesa ${tableId}:`, item.name);
  };

  return (
    <div className="tabletop-container">
      <h1>Mesa #{tableId}</h1>
      <h2>Nuestro Menú</h2>
      <div className="menu-grid">
        {menu.map(item => (
          <MenuItem
            key={item.id}
            item={item}
            onAddToCart={handleAddToCart}
          />
        ))}
      </div>
      <Cart items={cartItems} />
    </div>
  );
};

export default TabletopView;
